// // This flip-flop is designed to hold the value of 'd' when 'set' is high, and reset to 0 when 'reset' is high.
module top_module(input d, clk, set, reset, output reg q);always @(posedge clk or posedge reset or posedge set)
    if(reset)
	    q <= 0;
	else if(set)
	    q <= 1;
	else
	    q <= d;
endmodule
